                <button class="btn" onclick="alert()">Scopri</button>
            </div>
        </section>
        <section>
        <h2 style="color: #0ff;">Contattaci</h2>
        <form id="form" onsubmit="return inv()">
            <label for="nome">Nome</label>
            <input type="text" id="nome" name="nome" required placeholder="Il tuo nome">
            <label for="email">Email</label>
            <input type="email" id="email" name="email" required placeholder="La tua email">
            <label for="msg">Messaggio</label>
            <textarea id="msg" rows="4" required placeholder="Il tuo messaggio..."></textarea>
            <button class="btn" type="submit">Invia richiesta</button>
</form>
</section>
<div class="footer">
<p>�//Accesso al sistema quantistico</p>
